import React, { Component } from 'react';
import {
  View,
  Text,
  FlatList,
  TextInput,
  TouchableOpacity,
  ActivityIndicator,
  Alert,
  StyleSheet,
} from 'react-native';
import Header from '../components/Header';
import MessageItem from '../components/MessageItem';
import { getUserName } from '../utils/format';

export default class ThreadScreen extends Component {
  constructor(props) {
    super(props);
    this.state = {
      replies: [],
      loading: true,
      inputText: '',
      sending: false,
      pollTimer: null,
    };
  }

  componentDidMount() {
    this.loadReplies();
    this.startPolling();
  }

  componentWillUnmount() {
    this.stopPolling();
  }

  startPolling() {
    var self = this;
    var timer = setInterval(function () {
      self.pollReplies();
    }, 5000);
    this.setState({ pollTimer: timer });
  }

  stopPolling() {
    if (this.state.pollTimer) {
      clearInterval(this.state.pollTimer);
    }
  }

  async loadReplies() {
    var { slack, channel, parentMessage } = this.props;
    try {
      var res = await slack.conversationsReplies(channel.id, parentMessage.ts);
      this.setState({ replies: res.messages || [], loading: false });
    } catch (err) {
      this.setState({ loading: false });
      Alert.alert('Error', err.message);
    }
  }

  async pollReplies() {
    var { slack, channel, parentMessage } = this.props;
    var { loading } = this.state;
    if (loading) return;
    try {
      var res = await slack.conversationsReplies(channel.id, parentMessage.ts);
      this.setState({ replies: res.messages || [] });
    } catch (err) {
      // Silent
    }
  }

  async sendReply() {
    var { slack, channel, parentMessage } = this.props;
    var { inputText } = this.state;
    var text = inputText.trim();
    if (!text) return;

    this.setState({ sending: true });
    try {
      await slack.chatPostMessage(channel.id, text, parentMessage.ts);
      this.setState({ inputText: '', sending: false });
      this.loadReplies();
    } catch (err) {
      this.setState({ sending: false });
      Alert.alert('Error', err.message);
    }
  }

  render() {
    var { usersMap, currentUserId, onBack, parentMessage } = this.props;
    var { replies, loading, inputText, sending } = this.state;
    var self = this;
    var parentUser = getUserName(parentMessage.user, usersMap);

    return (
      <View style={styles.container}>
        <Header
          title="Thread"
          subtitle={'Started by ' + parentUser}
          onBack={onBack}
        />

        {loading ? (
          <View style={styles.center}>
            <ActivityIndicator size="large" color="#4A90D9" />
          </View>
        ) : (
          <FlatList
            ref={function (r) { self._list = r; }}
            data={replies}
            keyExtractor={function (item) { return item.ts; }}
            renderItem={function (obj) {
              return (
                <MessageItem
                  message={obj.item}
                  usersMap={usersMap}
                  currentUserId={currentUserId}
                />
              );
            }}
            onContentSizeChange={function () {
              if (self._list && replies.length > 0) {
                self._list.scrollToEnd({ animated: false });
              }
            }}
          />
        )}

        <View style={styles.inputRow}>
          <TextInput
            style={styles.input}
            placeholder="Reply..."
            placeholderTextColor="#555577"
            value={inputText}
            onChangeText={function (t) { self.setState({ inputText: t }); }}
            onSubmitEditing={function () { self.sendReply(); }}
            returnKeyType="send"
          />
          <TouchableOpacity
            style={[styles.sendBtn, (!inputText.trim() || sending) && styles.sendDisabled]}
            onPress={function () { self.sendReply(); }}
            disabled={!inputText.trim() || sending}
          >
            {sending ? (
              <ActivityIndicator size="small" color="#ffffff" />
            ) : (
              <Text style={styles.sendText}>Send</Text>
            )}
          </TouchableOpacity>
        </View>
      </View>
    );
  }
}

var styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#1a1a2e',
  },
  center: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
  inputRow: {
    flexDirection: 'row',
    alignItems: 'center',
    padding: 8,
    borderTopWidth: StyleSheet.hairlineWidth,
    borderTopColor: '#2a2a4e',
    backgroundColor: '#0e1726',
  },
  input: {
    flex: 1,
    backgroundColor: '#16213e',
    color: '#ffffff',
    fontSize: 14,
    paddingHorizontal: 12,
    paddingVertical: 8,
    borderRadius: 20,
    borderWidth: 1,
    borderColor: '#2a2a4e',
    marginRight: 8,
  },
  sendBtn: {
    backgroundColor: '#4A90D9',
    paddingHorizontal: 16,
    paddingVertical: 8,
    borderRadius: 20,
  },
  sendDisabled: {
    opacity: 0.4,
  },
  sendText: {
    color: '#ffffff',
    fontSize: 14,
    fontWeight: 'bold',
  },
});
